import{_ as e,o as a,c as t,j as r,a as p,a1 as n}from"./chunks/framework.Bp7r_-XI.js";const C=JSON.parse('{"title":"未来守护者","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/2.武器/远程武器/2.C级/未来守护者.md","filePath":"4.资源分区/7.物品与装备/2.武器/远程武器/2.C级/未来守护者.md"}'),s={name:"4.资源分区/7.物品与装备/2.武器/远程武器/2.C级/未来守护者.md"};function o(d,b,_,l,i,c){return a(),t("div",null,[...b[0]||(b[0]=[r("h1",{id:"未来守护者",tabindex:"-1"},[p("未来守护者 "),r("a",{class:"header-anchor",href:"#未来守护者","aria-label":'Permalink to "未来守护者"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：新秩序009")])])],-1),n('<h1 id="未来守护者-1" tabindex="-1">未来守护者 <a class="header-anchor" href="#未来守护者-1" aria-label="Permalink to &quot;未来守护者&quot;">​</a></h1><p>未来守护者<br> D+1500<br> 购买此技艺后，购买者便可以正常以武技/射击-专业：未来守护者科技使用墨丘利之炮/墨丘利之锤。在武器分类上，墨丘利之炮视为枪械，墨丘利之锤视为锤类武器</p><p>购买前提：未来守护者</p><p>C+2500<br> 科技本质<br> 皮尔特沃夫的科技结晶，进步之城的荣耀。塔利斯议员终究理解了自己的使命，也被迫接受了它，就如同所有委曲求全的普通人一般。他野心勃勃，却又无计可施，曾经的友谊、师生情谊以及理想已经烟消云散，他被迫守护，也只能守护。<br> 墨丘利之炮/墨丘利之锤是一件长杆式武器，这柄武器的首端能自由切换为能量炮和战锤。墨丘利之炮和墨丘利之锤都拥有独特的特性，它只能在两种形态中切换使用，无法同时展现两种状态。特殊的，墨丘利之锤使用独特的武技/射击专业-未来守护者科技进行攻击检定。墨丘利之炮/墨丘利之锤在本质上都视为一件C级科技本质的武器</p><p>墨丘利之炮<br> 13L<br> 射程200米<br> 这是一杆拥有暗黄色长柄，首端由二分聚能元件包裹海克斯科技电容核心构成的射击武器。它在一般情况下拥有3点破甲及【能量武器】特性<br> 墨丘利之炮由海克斯科技电容为核心驱动，本质上拥有无穷无尽的蕴藏能量，它无论在何时进行射击都无需消耗弹药。但特殊的，它也无法使用特殊弹药。<br> 通常情况下，墨丘利之炮会为持有者额外提供三个独特的招式，当使用墨丘利之炮进行一次攻击时，至少选用电能震荡/超能电荷中的一种才能进行一次攻击，并消耗对应的能量</p><p>电能震荡<br> 等级：C<br> 消耗能量：0<br> 成分：武器<br> 动作：如下<br> 射程：武器射程范围内<br> 效果：立即<br> 这个招式有且仅有使用墨丘利之炮并以标准动作或至少为标准动作进行一次攻击检定时才能使用。立即使用墨丘利之炮对射程范围内的一个角色进行一次充满电能的电荷团射击，这颗电荷团在击中第一个目标时会立即展开爆裂，溅射伤害该目标周围7.5米直径内的所有角色。这颗电荷团在爆裂时会削减所有被命中者的反射豁免持续一轮，降低的数量等同于持有者当前支线等级的一半（向上取整）</p><p>超能电荷<br> 等级：C<br> 消耗能量：0<br> 成分：武器<br> 动作：如下<br> 射程：武器射程范围内<br> 效果：立即<br> 这个招式有且仅有使用墨丘利之炮并以标准动作或至少为标准动作进行一次攻击检定时才能使用。立即使用墨丘利之炮对射程范围内的一名角色进行一次三连射攻击（视为一次攻击），此次攻击可以选择将墨丘利之炮拥有的破甲转换成高速，也可以选择将高速转换为破甲。若被攻击者此时的基础防御及闪避防御均完全不存在，则此次射击发射的能量束会额外将其中造成的最多6点严重伤害转化为韧性</p><p>加速之门<br> 等级：C<br> 消耗能量：0<br> 成分：武器<br> 动作：迅捷<br> 射程：特殊<br> 效果：立即<br> 立即在使用者身前展开一道加速之门，这道加速之门会在使用者穿过时额外为其提供10点移速。若使用者当回合使用电能震荡且电荷团穿过此道加速之门，则额外使其作用范围扩大一倍</p><p>墨丘利之锤<br> 12L<br> 这是一柄拥有暗黄色长柄，首端由分布在两侧的锤击增幅金属包裹海克斯电容核心构成的战锤。它在一般情况下拥有【重击3】及威猛3<br> （【重击3】：当使用者进行一次攻击时，若该武器拥有的威猛成功破除被攻击者的洞察/格挡防御，则每成功破除一点便可以选择减少此次攻击的1DP，并转化为等量的附加，最高不超过3）<br> 通常情况下，墨丘利之锤均需双手持用，它至少需要2点力量上的传奇附加才能正常使用。墨丘利之锤会为持有者额外提供三个独特的招式，当使用墨丘利之锤进行一次攻击时，至少选用苍穹之跃/雷霆一击中的一种才能进行一次攻击，并消耗对应的能量</p><p>苍穹之跃<br> 等级：C<br> 消耗能量：0<br> 成分：武器<br> 动作：如下<br> 射程：以自身为中心5米范围内<br> 效果：立即<br> 这个招式有且仅有使用墨丘利之锤并以标准动作或至少为标准动作进行一次攻击检定时才能使用。选择一个在单次移动范围内的目标立即使用，使用者高高跃起到该目标面前（这视为进行了一次移动），随即砸下战锤，进行此次攻击时，墨丘利之锤原本的【重击3】变为【重击5】</p><p>闪电领域<br> 等级：C<br> 消耗能量：0<br> 成分：武器<br> 动作：迅捷<br> 射程：无<br> 效果：立即<br> 使用一个迅捷动作，立即在自身周围打开一团由闪电组成的屏障，任何对你发起近战攻击的目标都会额外受到闪电领域的攻击，闪电领域的伤害为1L，对方需使用反射豁免进行对抗。特殊的，这个技能可以额外投入经验进行升级，每投入3XP就可以将这个伤害数目提高1L。这个屏障将持续存在一轮</p><p>雷霆一击<br> 等级：C<br> 消耗能量：0<br> 成分：武器<br> 动作：如下<br> 射程：接触范围<br> 效果：立即<br> 这个招式有且仅有使用墨丘利之锤并以标准动作或至少为标准动作进行一次攻击检定时才能使用。立即对攻击范围内指定的敌人进行一次锤击，并令其对此次攻击造成的成功数进行一次反射豁免，将其击退二者差值+5米。特殊的，这个技能可以在使用一次苍穹之跃后在那一轮的回合外使用一个反射动作以调用下个回合标准动作使用此招式</p><hr><p>Copyright ? 2023 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',14)])])}const f=e(s,[["render",o]]);export{C as __pageData,f as default};
